type NestedObject = {
  [key: string]: string | NestedObject;
};

function logNestedStrings(obj: NestedObject): void {
  for (const key in obj) {
    const value = obj[key];
    if (typeof value === 'string') {
      console.log(value);
    } else {
      logNestedStrings(value);
    }
  }
}

type FlatObject = {
  [key: string]: string;
};

function flattenNestedObject(
  obj: NestedObject,
  prefix: string = ''
): FlatObject {
  let result: FlatObject = {};

  for (const key in obj) {
    const value = obj[key];
    const newKey = prefix ? `${prefix}.${key}` : key;

    if (typeof value === 'string') {
      result[newKey] = value;
    } else {
      const nested = flattenNestedObject(value, newKey);
      result = { ...result, ...nested };
    }
  }

  return result;
}

const nested: NestedObject = {
  user: {
    name: 'Alice',
    address: {
      city: 'Wonderland',
      zip: '12345'
    }
  },
  status: 'active'
};

const flat = flattenNestedObject(nested);
console.log(flat);
